mapper.select:
SELECT CASE WHEN RN.DISPLAYED_DATE > RN.UPDATE_TIME THEN RN.DISPLAYED_DATE ELSE RN.UPDATE_TIME END AS RELEASE_NOTE_LATEST_TIME, RNR.LAST_READ_TIME AS LAST_READ_TIME, RNR.NEXT_DISP_FLG AS NEXT_DISP_FLG FROM ( SELECT MAX(DISPLAYED_DATE) AS DISPLAYED_DATE, MAX(UPDATE_TIME) AS UPDATE_TIME FROM CORDYS.RELEASE_NOTE
DISPLAYED_DATE <= SYSDATE
) RN LEFT OUTER JOIN RELEASE_NOTE_READ RNR ON RNR.USER_ID = #{userId}
